#!runts
import {produce} from "immer";
import {Item,findById,decode} from "../todo.js"
export async function main(this:any){
  const root=decode(this.resolve(this.$home).rel("todo.txt").text());
  console.log(root)
  let id=root[2].sub[0].id;
  
  const r2=produce(root,(d)=>{
    const fth=findById(d,id);
    fth!.title="&&&5"
  })
  return r2
}